class Solution {
    public int peopleAwareOfSecret(int n, int delay, int forget) {
        long[] dp = new long[n + 1];
        dp[0] = 1;
        long MOD = 1000000007;
        for (int i = 1; i <= n; i++) {
            for (int j = Math.max(0, i - delay); j < i; j++) {
                if (i - j >= forget) {
                    dp[i] = (dp[i] + dp[j]) % MOD;
                }
            }
        }
        long result = 0;
        for (int i = 0; i <= n; i++) {
            result = (result + dp[i]) % MOD;
        }
        return (int) result;
    }
}
